import React, { useEffect, useState } from 'react';
import { ClipboardList, Search, Loader, AlertCircle, Eye } from 'lucide-react';
import api from '../../services/api';

const statusBadge = (status) => {
  const map = {
    paid:      'bg-green-100 text-green-700',
    pending:   'bg-yellow-100 text-yellow-700',
    cancelled: 'bg-red-100 text-red-600',
  };
  return map[(status || 'paid').toLowerCase()] || 'bg-slate-100 text-slate-600';
};

const StaffOrders = () => {
  const [orders, setOrders]   = useState([]);
  const [search, setSearch]   = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    api.get('/sales')
      .then(r => setOrders(r.data || []))
      .catch(() => setError('Failed to load orders'))
      .finally(() => setLoading(false));
  }, []);

  const filtered = orders.filter(o =>
    String(o.saleId || '').includes(search) ||
    (o.customerName || '').toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-6 text-white shadow-lg">
        <div className="flex items-center gap-3">
          <ClipboardList className="w-6 h-6" />
          <div>
            <h1 className="text-2xl font-bold">Orders</h1>
            <p className="text-blue-100 text-sm">View all sales transactions</p>
          </div>
        </div>
      </div>

      {error && (
        <div className="flex items-center gap-3 p-4 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
          <AlertCircle className="w-5 h-5 flex-shrink-0" />{error}
        </div>
      )}

      {/* Table Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex items-center gap-3">
          <div className="relative flex-1 max-w-xs">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search by ID or customer…"
              className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
            />
          </div>
          <span className="text-sm text-slate-400 ml-auto">{filtered.length} records</span>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-20"><Loader className="w-7 h-7 text-blue-500 animate-spin" /></div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-slate-50">
                <tr>
                  {['#', 'Date', 'Customer', 'Amount', 'Payment', 'Status', ''].map(h => (
                    <th key={h} className="px-5 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filtered.length === 0 ? (
                  <tr><td colSpan={7} className="py-16 text-center text-slate-400">No orders found</td></tr>
                ) : filtered.map((o, i) => (
                  <tr key={o.saleId || i} className="hover:bg-slate-50 transition-colors">
                    <td className="px-5 py-3 font-mono text-xs text-slate-400">#{o.saleId || i+1}</td>
                    <td className="px-5 py-3 text-slate-600">{o.dateCreated ? new Date(o.dateCreated).toLocaleDateString() : '–'}</td>
                    <td className="px-5 py-3 font-medium text-slate-800">{o.customerName || 'Walk-in'}</td>
                    <td className="px-5 py-3 font-bold text-slate-800">${(o.amount||0).toFixed(2)}</td>
                    <td className="px-5 py-3 text-slate-600">{o.paymentMethod || 'Cash'}</td>
                    <td className="px-5 py-3">
                      <span className={`px-2.5 py-1 rounded-full text-xs font-medium capitalize ${statusBadge(o.status)}`}>
                        {o.status || 'Paid'}
                      </span>
                    </td>
                    <td className="px-5 py-3">
                      <button
                        onClick={() => setSelected(o)}
                        className="p-1.5 hover:bg-blue-50 rounded-lg text-blue-500 transition-colors"
                      ><Eye className="w-4 h-4" /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selected && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 px-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="font-bold text-slate-800">Order #{selected.saleId}</h3>
              <button onClick={() => setSelected(null)} className="p-1.5 hover:bg-slate-100 rounded-lg">
                <AlertCircle className="w-4 h-4 text-slate-400" />
              </button>
            </div>
            <div className="space-y-2 text-sm">
              <div className="flex justify-between py-2 border-b border-slate-100">
                <span className="text-slate-500">Customer</span>
                <span className="font-medium">{selected.customerName || 'Walk-in'}</span>
              </div>
              <div className="flex justify-between py-2 border-b border-slate-100">
                <span className="text-slate-500">Date</span>
                <span className="font-medium">{new Date(selected.dateCreated).toLocaleString()}</span>
              </div>
              <div className="flex justify-between py-2 border-b border-slate-100">
                <span className="text-slate-500">Payment</span>
                <span className="font-medium">{selected.paymentMethod || 'Cash'}</span>
              </div>
              <div className="flex justify-between py-2">
                <span className="text-slate-500">Total</span>
                <span className="font-bold text-emerald-600 text-lg">${(selected.amount||0).toFixed(2)}</span>
              </div>
            </div>
            <button
              onClick={() => setSelected(null)}
              className="w-full py-2.5 bg-slate-100 hover:bg-slate-200 rounded-xl text-sm font-medium text-slate-700 transition-colors"
            >Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffOrders;
